<?php require APP_ROOT.'/app/views/layouts/header.php';?><h3>Candidate Review</h3><div class="card"><div class="card-body"><h4><?=htmlspecialchars($candidate['name'])?></h4><p><b>Mobile:</b> <?=htmlspecialchars($candidate['mobile'])?></p><p><b>Job Type:</b> <?=htmlspecialchars($candidate['job_type'])?></p><p><b>Skills:</b> <?=htmlspecialchars($candidate['skills'])?></p><p><b>Experience:</b> <?=htmlspecialchars($candidate['experience'])?></p><p><b>Preferred Location:</b> <?=htmlspecialchars($candidate['preferred_location'])?></p><form method="post" action="<?=BASE_URL?>/candidates/status"><input type="hidden" name="id" value="<?=$candidate['id']?>"><div class="input-group"><select class="form-select" name="status"><?php foreach(['new','under_review','verified','shortlisted','sent','selected','deployed','rejected'] as $st):?><option value="<?=$st?>" <?=$candidate['status']==$st?'selected':''?>><?=ucwords(str_replace('_',' ',$st))?></option><?php endforeach;?></select><button class="btn btn-success">Update Status</button></div></form></div></div><?php require APP_ROOT.'/app/views/layouts/footer.php';?>